print("=== VERIFY 6e ===")
for b in books:
    if b["id"] != 241:
        continue
    desc_len = len(b["description"])
    print("desc=%d %s" % (desc_len, "OK" if 125 <= desc_len <= 150 else "BAD"))
    issues = []
    for i, t in enumerate(b["thoughts"]):
        total = len(t["title"]) + len(t["example"])
        s = "OK" if 700 <= total <= 800 else ("SHORT=%d" % total if total < 700 else "LONG=%d" % total)
        if s != "OK" or "life" in t:
            issues.append("t%d %s" % (i, s))
    if issues:
        for x in issues:
            print(x)
    else:
        print("thoughts: ALL OK")
